const ARSENAL_DATA = [
  {
    name: 'LANGUAGES',
    icons: [PythonIcon, CPlusPlusIcon, JavaIcon, TypeScriptIcon, PhpIcon],
    items: ['PYTHON', 'C++', 'JAVA', 'TYPESCRIPT', 'PHP']
  },
  {
    name: 'FRAMEWORKS & LIBS',
    icons: [ReactIcon, SpringBootIcon, PyTorchIcon, NumPyIcon, PandasIcon],
    items: ['REACT', 'SPRING BOOT', 'PYTORCH', 'NUMPY', 'PANDAS']
  },
  {
    name: 'DATABASES & DEVOPS',
    icons: [MongoDbIcon, MySqlIcon, PostgresIcon, OracleDbIcon, DockerIcon, GitIcon, CiCdIcon],
    items: ['MONGODB', 'MYSQL', 'POSTGRES', 'ORACLE DB', 'DOCKER', 'GIT', 'CI/CD']
  }
];

const RING_RADII = [1.65, 2.25, 2.85];

function TechIcon({ icon: Icon, position, opacity, isFocused, size = 0.4, glitch = 0 }) {
  const texture = useMemo(() => {
    const color = isFocused ? "#ffffff" : "#ffffff";
    let svgString = renderToStaticMarkup(
      <Icon color={color} size={64} strokeWidth={1.5} />
    );

    // Ensure the SVG element contains the XML namespace so browsers can render it inside an Image
    if (!svgString.includes('xmlns="http://www.w3.org/2000/svg"')) {
      svgString = svgString.replace('<svg ', '<svg xmlns="http://www.w3.org/2000/svg" ');
    }

    const canvas = document.createElement('canvas');
    canvas.width = 256;
    canvas.height = 256;
    const ctx = canvas.getContext('2d');
    const img = new Image();

    // Use encodeURIComponent which is robust and safe from base64/btoa ASCII errors
    img.src = `data:image/svg+xml;utf8,${encodeURIComponent(svgString)}`;

    const tex = new THREE.CanvasTexture(canvas);
    img.onload = () => {
      ctx.clearRect(0, 0, 256, 256);
      ctx.drawImage(img, 32, 32, 192, 192);
      tex.needsUpdate = true;
    };
    return tex;
  }, [Icon, isFocused]);

  const finalSize = isFocused ? size * 1.25 : size;
  const meshRef = useRef();

  useFrame((state) => {
    if (!meshRef.current || glitch <= 0) return;
    meshRef.current.position.x = position[0] + (Math.random() - 0.5) * glitch * 0.1;
    meshRef.current.position.y = position[1] + (Math.random() - 0.5) * glitch * 0.1;
    meshRef.current.visible = Math.random() > glitch * 0.3;
  });

  return (
    <mesh ref={meshRef} position={position}>
      <planeGeometry args={[finalSize, finalSize]} />
      <meshBasicMaterial
        map={texture}
        transparent
        opacity={opacity}
        depthWrite={false}
        toneMapped={false}
      />
    </mesh>
  );
}

function CurvedText({ text, radius, opacity }) {
  const chars = text.split("");
  const charSpacing = 0.14;

  return (
    <group>
      {chars.map((char, i) => {
        const totalChars = chars.length;
        const angleOffset = ((totalChars - 1) / 2 - i) * charSpacing;
        const angle = Math.PI / 2 + angleOffset;
        const x = Math.cos(angle) * radius;
        const y = Math.sin(angle) * radius;
        const rotationZ = angle - Math.PI / 2;

        return (
          <Text
            key={i}
            position={[x, y, 0]}
            rotation={[0, 0, rotationZ]}
            fontSize={0.24}
            font="/Orbitron-VariableFont_wght.ttf"
            color="#ef4bfb"
            fillOpacity={opacity * 0.8}
            outlineWidth={0.015}
            outlineColor="#ef4bfb"
            outlineOpacity={opacity * 0.4}
            textAlign="center"
            anchorX="center"
            anchorY="middle"
          >
            {char.toUpperCase()}
          </Text>
        );
      })}
    </group>
  );
}

function OrbitalRing({ items, icons, radius, isActive, focusIndex, opacity }) {
  const segmentWidth = 0.5;
  const gap = 0.04;

  return (
    <group>
      <mesh>
        <ringGeometry args={[radius - segmentWidth * 0.5, radius + segmentWidth * 0.5, 64]} />
        <meshBasicMaterial
          transparent
          opacity={opacity * 0.15}
          color="#4b0082"
          side={THREE.DoubleSide}
        />
      </mesh>

      <group>
        {items.map((item, i) => {
          const segmentAngle = (Math.PI * 2 / items.length);
          const startAngle = (i * segmentAngle) + Math.PI / 2 - (segmentAngle / 2) + gap / 2;
          const lengthAngle = segmentAngle - gap;
          const isFocused = isActive && i === focusIndex;

          const iconAngle = i * segmentAngle + Math.PI / 2;
          const iconX = Math.cos(iconAngle) * radius;
          const iconY = Math.sin(iconAngle) * radius;

          return (
            <group key={item}>
              <mesh position={[0, 0, 0.01]}>
                <ringGeometry args={[
                  radius - segmentWidth * (isFocused ? 0.55 : 0.5),
                  radius + segmentWidth * (isFocused ? 0.55 : 0.5),
                  64, 1,
                  startAngle,
                  lengthAngle
                ]} />
                <meshBasicMaterial
                  transparent
                  opacity={opacity * (isFocused ? 0.9 : 0.2)}
                  color={isFocused ? "#ff00ff" : (isActive ? "#ef4bfb" : "#4b0082")}
                  depthWrite={false}
                  side={THREE.DoubleSide}
                  toneMapped={false}
                />
              </mesh>

              <TechIcon
                icon={icons[i % icons.length]}
                position={[iconX, iconY, 0.15]}
                opacity={opacity * (isFocused ? 1 : 0.4)}
                isFocused={isFocused}
              />
            </group>
          );
        })}
      </group>
    </group>
  );
}

function ControlIndicator({ opacity }) {
  const gap = 0.3;
  const iconSize = 0.35;

  return (
    <group position={[-2.4, -3.2, 0]}>
      <group position={[0, 0, 0]}>
        <TechIcon icon={ChevronUp} position={[0, gap, 0]} opacity={opacity * 0.9} size={iconSize} isFocused={true} />
        <TechIcon icon={ChevronDown} position={[0, -gap, 0]} opacity={opacity * 0.9} size={iconSize} isFocused={true} />
        <TechIcon icon={ChevronLeft} position={[-gap, 0, 0]} opacity={opacity * 0.9} size={iconSize} isFocused={true} />
        <TechIcon icon={ChevronRight} position={[gap, 0, 0]} opacity={opacity * 0.9} size={iconSize} isFocused={true} />
      </group>

      <Text
        position={[0, -0.7, 0]}
        fontSize={0.09}
        font="/Orbitron-VariableFont_wght.ttf"
        color="#ffffff"
        fillOpacity={opacity * 0.8}
        letterSpacing={0.2}
      >
        USE ARROWS TO NAVIGATE
      </Text>
    </group>
  );
}

export function ArsenalGallery() {
  const groupRef = useRef();
  const ring0Ref = useRef();
  const ring1Ref = useRef();
  const ring2Ref = useRef();
  const labelsRef = useRef();
  const coreRef = useRef();
  const scroll = useScroll();
  const pageIndex = getPortfolioPageIndex('arsenal');
  const pageCount = PORTFOLIO_PAGES.length;

  const [activeLevel, setActiveLevel] = useState(0);
  const [focusIndices, setFocusIndices] = useState(ARSENAL_DATA.map(() => 0));
  const [layerOpacities, setLayerOpacities] = useState([0, 0, 0, 0, 0]);
  const [transitionGlitch, setTransitionGlitch] = useState(0);
  const clickSoundRef = useRef(null);

  useEffect(() => {
    clickSoundRef.current = new Audio('/audio/click.mp3');
    clickSoundRef.current.volume = 0.2;
  }, []);

  // Sync selection to arsenalState for the 2D overlay
  useEffect(() => {
    arsenalState.activeLevel = activeLevel;
    arsenalState.focusIndices = focusIndices;
  }, [activeLevel, focusIndices]);

  useEffect(() => {
    const handleKeyDown = (e) => {
      const offset = scroll.offset;
      const pageOffset = getRelativeOffset(offset, pageIndex, pageCount);
      if (pageOffset < 0.3 || pageOffset > 0.7) return;

      if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
        // Play click sound
        if (clickSoundRef.current) {
          clickSoundRef.current.currentTime = 0;
          clickSoundRef.current.play().catch(() => { });
        }
      }

      const triggerGlitch = () => setTransitionGlitch(1.0);

      if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
        const dir = e.key === 'ArrowUp' ? 1 : -1;
        const nextLevel = clamp(activeLevel + dir, 0, ARSENAL_DATA.length - 1);

        if (nextLevel !== activeLevel) {
          triggerGlitch();
          setFocusIndices((prev) => {
            const next = [...prev];
            const oldLength = ARSENAL_DATA[activeLevel].items.length;
            const newLength = ARSENAL_DATA[nextLevel].items.length;
            const oldIndex = prev[activeLevel];
            const nearestIndex = Math.round((oldIndex / oldLength) * newLength) % newLength;
            next[nextLevel] = nearestIndex;
            return next;
          });
          setActiveLevel(nextLevel);
        }
      } else if (e.key === 'ArrowLeft') {
        triggerGlitch();
        setFocusIndices((prev) => {
          const next = [...prev];
          const items = ARSENAL_DATA[activeLevel].items;
          next[activeLevel] = (next[activeLevel] + 1) % items.length;
          return next;
        });
      } else if (e.key === 'ArrowRight') {
        triggerGlitch();
        setFocusIndices((prev) => {
          const next = [...prev];
          const items = ARSENAL_DATA[activeLevel].items;
          next[activeLevel] = (next[activeLevel] - 1 + items.length) % items.length;
          return next;
        });
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [activeLevel, scroll, pageIndex, pageCount]);

  const LAYERS_EXIT_CONFIG = useMemo(() => [
    { start: 0.50, end: 0.65 }, // Layer 0: CurvedText & ControlIndicator
    { start: 0.55, end: 0.75 }, // Layer 1: Ring 2 (Protocols)
    { start: 0.65, end: 0.85 }, // Layer 2: Ring 1 (Tools)
    { start: 0.75, end: 0.95 }, // Layer 3: Ring 0 (Foundation)
    { start: 0.85, end: 1.00 }, // Layer 4: Central Core
  ], []);

  useFrame((state, delta) => {
    if (!groupRef.current) return;
    const offset = scroll.offset;
    const pageOffset = getRelativeOffset(offset, pageIndex, pageCount);

    const entranceStart = 0.3;
    const entranceEnd = 0.5;
    const entranceProgress = clamp((pageOffset - entranceStart) / (entranceEnd - entranceStart), 0, 1);

    const nextOpacities = LAYERS_EXIT_CONFIG.map((config) => {
      if (pageOffset < 0.5) {
        return entranceProgress;
      }
      const exitProgress = clamp((pageOffset - config.start) / (config.end - config.start), 0, 1);
      return entranceProgress * (1.0 - exitProgress);
    });

    let changed = false;
    for (let i = 0; i < 5; i++) {
      if (Math.abs(nextOpacities[i] - layerOpacities[i]) > 0.001) {
        changed = true;
        break;
      }
    }
    if (changed) {
      setLayerOpacities(nextOpacities);
    }

    LAYERS_EXIT_CONFIG.forEach((config, i) => {
      let glitch = 0;
      let opacityVal = nextOpacities[i];

      if (pageOffset >= 0.5) {
        const exitProgress = clamp((pageOffset - config.start) / (config.end - config.start), 0, 1);
        glitch = Math.sin(exitProgress * Math.PI) * exitProgress;
      }

      let ref;
      if (i === 0) ref = labelsRef;
      else if (i === 1) ref = ring2Ref;
      else if (i === 2) ref = ring1Ref;
      else if (i === 3) ref = ring0Ref;
      else if (i === 4) ref = coreRef;

      if (ref && ref.current) {
        if (glitch > 0.01) {
          ref.current.position.x = (Math.random() - 0.5) * glitch * 0.5;
          ref.current.position.y = (Math.random() - 0.5) * glitch * 0.5;
          ref.current.visible = Math.random() > glitch * 0.45;
        } else {
          ref.current.position.set(0, 0, 0);
          ref.current.visible = opacityVal > 0.01;
        }
      }
    });

    if (transitionGlitch > 0.01) {
      setTransitionGlitch(THREE.MathUtils.lerp(transitionGlitch, 0, delta * 12));
    } else if (transitionGlitch !== 0) {
      setTransitionGlitch(0);
    }

    const isAnyVisible = nextOpacities.some((op) => op > 0.01);
    groupRef.current.visible = isAnyVisible;
    groupRef.current.scale.setScalar(entranceProgress);
    groupRef.current.rotation.y = -0.4;
  });

  const focusedData = ARSENAL_DATA[activeLevel];
  const focusedIcon = focusedData.icons[focusIndices[activeLevel] % focusedData.icons.length];
  const focusedItem = focusedData.items[focusIndices[activeLevel]];

  return (
    <group ref={groupRef} position={[4, 0, 0]}>
      {ARSENAL_DATA.map((levelData, i) => {
        const opacityIdx = 3 - i;
        let ringRef;
        if (i === 0) ringRef = ring0Ref;
        else if (i === 1) ringRef = ring1Ref;
        else if (i === 2) ringRef = ring2Ref;

        return (
          <group key={levelData.name} ref={ringRef}>
            <OrbitalRing
              items={levelData.items}
              icons={levelData.icons}
              radius={RING_RADII[i]}
              isActive={activeLevel === i}
              focusIndex={focusIndices[i]}
              opacity={layerOpacities[opacityIdx]}
            />
          </group>
        );
      })}

      <group ref={labelsRef}>
        <CurvedText text="MY SKILLS" radius={3.3} opacity={layerOpacities[0]} />
        <ControlIndicator opacity={layerOpacities[0]} />
      </group>

      <group ref={coreRef}>
        <mesh>
          <circleGeometry args={[1.3, 64]} />
          <meshBasicMaterial
            transparent
            opacity={layerOpacities[4] * 0.15}
            color="#d900ff"
            depthWrite={false}
          />
        </mesh>
        <mesh>
          <ringGeometry args={[1.25, 1.3, 64]} />
          <meshBasicMaterial
            transparent
            opacity={layerOpacities[4] * 0.8}
            color="#ff00ff"
            depthWrite={false}
          />
        </mesh>

        <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
          <group position={[0, 0, 0.2]}>
            <TechIcon
              icon={focusedIcon}
              position={[0, 0.1, 0]}
              opacity={layerOpacities[4]}
              isFocused={true}
              size={0.8}
              glitch={transitionGlitch}
            />

            <Text
              fontSize={0.15}
              position={[0, -0.6, 0]}
              font="/Orbitron-VariableFont_wght.ttf"
              color="#ef4bfb"
              fillOpacity={layerOpacities[4] * (transitionGlitch > 0 && Math.random() > 0.5 ? 0.3 : 1)}
              textAlign="center"
              anchorY="middle"
              maxWidth={2.0}
              depthTest={false}
            >
              {focusedItem}
            </Text>
          </group>
        </Float>
      </group>
    </group>
  );
}
